import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            int N = Integer.parseInt(br.readLine().trim());
            String s = br.readLine().trim();
            int cnt = 0;
            boolean hard = false;
            for (int i = 0; i < s.length(); i++) {
                char c = s.charAt(i);
                if (c=='a'||c=='e'||c=='i'||c=='o'||c=='u') cnt = 0;
                else { cnt++; if (cnt >= 4) { hard = true; break; } }
            }
            out.append(hard ? "NO" : "YES").append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().split()
    it = iter(data)
    T = int(next(it))
    out = []
    vowels = set('aeiou')
    for _ in range(T):
        N = int(next(it))
        s = next(it)
        cnt = 0
        hard = False
        for ch in s:
            if ch in vowels:
                cnt = 0
            else:
                cnt += 1
                if cnt >= 4:
                    hard = True
                    break
        out.append('NO' if hard else 'YES')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

